1433: // RunPreBindPlugins runs the set of configured prebind plugins. It returns a
1434: // failure (bool) if any of the plugins returns an error. It also returns an
1435: // error containing the rejection message or the error occurred in the plugin.
1436: func (f *frameworkImpl) RunPreBindPlugins(ctx context.Context, state fwk.CycleState, pod *v1.Pod, nodeName string) (status *fwk.Status) {
1437: 	startTime := time.Now()
1438: 	defer func() {
1439: 		metrics.FrameworkExtensionPointDuration.WithLabelValues(metrics.PreBind, status.Code().String(), f.profileName).Observe(metrics.SinceInSeconds(startTime))
1440: 	}()
1441: 	logger := klog.FromContext(ctx)
1442: 	verboseLogs := logger.V(4).Enabled()
1443: 	if verboseLogs {
1444: 		logger = klog.LoggerWithName(logger, "PreBind")
1445: 		logger = klog.LoggerWithValues(logger, "node", klog.ObjectRef{Name: nodeName})
1446: 	}
1447: 
1448: 	ctx, cancel := context.WithCancelCause(ctx)
1449: 	defer cancel(errors.New("RunPreBindPlugins has completed"))
1450: 	statusCh := parallelize.NewResultChannel[*fwk.Status]()
1451: 	skippedPlugins := state.GetSkipPreBindPlugins()
1452: 	parallelPlugins := state.GetParallelPreBindPlugins()
1453: 
1454: 	// run operates directly on the plugin.
1455: 	run := func(pl fwk.PreBindPlugin) *fwk.Status {
1456: 		ctx := ctx
1457: 		if verboseLogs {
1458: 			logger := klog.LoggerWithName(logger, pl.Name())
1459: 			ctx = klog.NewContext(ctx, logger)
1460: 		}
1461: 		plStatus := f.runPreBindPlugin(ctx, pl, state, pod, nodeName)
1462: 		if !plStatus.IsSuccess() {
1463: 			if plStatus.IsRejected() {
1464: 				logger.V(4).Info("Pod rejected by PreBind plugin", "pod", klog.KObj(pod), "node", nodeName, "plugin", pl.Name(), "status", plStatus.Message())
1465: 				plStatus.SetPlugin(pl.Name())
1466: 				return plStatus
1467: 			}
1468: 			err := plStatus.AsError()
1469: 			if errors.Is(err, context.Canceled) {
1470: 				err = context.Cause(ctx)
1471: 			}
1472: 
1473: 			logger.Error(err, "Plugin failed", "plugin", pl.Name(), "pod", klog.KObj(pod), "node", nodeName)
1474: 			return fwk.AsStatus(fmt.Errorf("running PreBind plugin %q: %w", pl.Name(), err))
1475: 		}
1476: 		return nil
1477: 	}
1478: 
1479: 	pluginGroups := f.getPreBindPluginGroups(state, skippedPlugins, parallelPlugins)
1480: 	for _, plugins := range pluginGroups {
1481: 		// If there is just a single plugin in the group, running it in a separate goroutine
1482: 		// does not provide any benefit.
1483: 		if len(plugins) == 1 {
1484: 			if status := run(plugins[0]); status != nil {
1485: 				return status
1486: 			}
1487: 			continue
1488: 		}
1489: 		f.Parallelizer().Until(ctx, len(plugins), func(index int) {
1490: 			if status := run(plugins[index]); !status.IsSuccess() {
1491: 				statusCh.SendWithCancel(status, func() {
1492: 					cancel(errors.New("some other PreBind operation failed"))
1493: 				})
1494: 			}
1495: 		}, metrics.PreBind)
1496: 		if status := statusCh.Receive(); !status.IsSuccess() {
1497: 			return status
1498: 		}
1499: 	}
1500: 	return nil
1501: }
