1503: // getPreBindPluginGroups chunks the plugins implementing the PreBind extension point
1504: // into groups of plugins that can be run in parallel.
1505: // The returned value consists of non-skipped plugins only.
1506: func (f *frameworkImpl) getPreBindPluginGroups(state fwk.CycleState, skippedPlugins, parallelPlugins sets.Set[string]) [][]fwk.PreBindPlugin {
1507: 	var groups [][]fwk.PreBindPlugin
1508: 	var group []fwk.PreBindPlugin
1509: 	for _, pl := range f.preBindPlugins {
1510: 		if parallelPlugins.Has(pl.Name()) {
1511: 			if !skippedPlugins.Has(pl.Name()) {
1512: 				group = append(group, pl)
1513: 			}
1514: 			continue
1515: 		}
1516: 		if len(group) > 0 {
1517: 			groups = append(groups, group)
1518: 			group = nil
1519: 		}
1520: 		if !skippedPlugins.Has(pl.Name()) {
1521: 			groups = append(groups, []fwk.PreBindPlugin{pl})
1522: 		}
1523: 	}
1524: 	if len(group) > 0 {
1525: 		groups = append(groups, group)
1526: 	}
1527: 	return groups
1528: }
