1540: // RunPreBindPreFlights runs the set of configured PreBindPreFlight functions from PreBind plugins.
1541: // The returning value is:
1542: // - Success: one or more plugins return success, meaning, some PreBind plugins will work for this pod.
1543: // - Skip: all plugins return skip.
1544: // - Error: any plugin return error.
1545: func (f *frameworkImpl) RunPreBindPreFlights(ctx context.Context, state fwk.CycleState, pod *v1.Pod, nodeName string) (status *fwk.Status) {
1546: 	startTime := time.Now()
1547: 	defer func() {
1548: 		metrics.FrameworkExtensionPointDuration.WithLabelValues(metrics.PreBindPreFlight, status.Code().String(), f.profileName).Observe(metrics.SinceInSeconds(startTime))
1549: 	}()
1550: 	logger := klog.FromContext(ctx)
1551: 	verboseLogs := logger.V(4).Enabled()
1552: 	if verboseLogs {
1553: 		logger = klog.LoggerWithName(logger, "PreBindPreFlight")
1554: 		logger = klog.LoggerWithValues(logger, "node", klog.ObjectRef{Name: nodeName})
1555: 	}
1556: 	skipPlugins := sets.New[string]()
1557: 	parallelPlugins := sets.New[string]()
1558: 	returningStatus := fwk.NewStatus(fwk.Skip)
1559: 	for _, pl := range f.preBindPlugins {
1560: 		ctx := ctx
1561: 		if verboseLogs {
1562: 			logger := klog.LoggerWithName(logger, pl.Name())
1563: 			ctx = klog.NewContext(ctx, logger)
1564: 		}
1565: 		result, status := f.runPreBindPreFlight(ctx, pl, state, pod, nodeName)
1566: 		if result != nil && result.AllowParallel {
1567: 			parallelPlugins.Insert(pl.Name())
1568: 		}
1569: 		switch {
1570: 		case status.Code() == fwk.Error:
1571: 			err := status.AsError()
1572: 			logger.Error(err, "Plugin failed", "plugin", pl.Name(), "pod", klog.KObj(pod), "node", nodeName)
1573: 			return fwk.AsStatus(fmt.Errorf("running PreBindPreFlight %q: %w", pl.Name(), err))
1574: 		case status.IsSuccess():
1575: 			// We return success when one or more plugins return success.
1576: 			returningStatus = nil
1577: 		case status.IsSkip():
1578: 			skipPlugins.Insert(pl.Name())
1579: 		default:
1580: 			// Other statuses are unexpected
1581: 			return fwk.AsStatus(fmt.Errorf("PreBindPreFlight %s returned %q, which is unsupported. It is supposed to return Success, Skip, or Error status", pl.Name(), status.Code()))
1582: 		}
1583: 	}
1584: 	state.SetSkipPreBindPlugins(skipPlugins)
1585: 	state.SetParallelPreBindPlugins(parallelPlugins)
1586: 	return returningStatus
1587: }
